class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] answer = new int[queries.length];
        int idx = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                answer[idx++] = queryCount(nums, l, r, k);
            } else {
                int idx1 = (int) query[1];
                long val = query[2];
                nums[idx1] = val;
            }
        }
        return Arrays.copyOf(answer, idx);
    }

    private int queryCount(long[] nums, int l, int r, int k) {
        int count = 0;
        for (int i = l; i <= r; i++) {
            if (popcount(nums[i]) == k) {
                count++;
            }
        }
        return count;
    }

    private int popcount(long x) {
        int count = 0;
        while (x > 0) {
            count += x & 1;
            x >>= 1;
        }
        return count;
    }
}
